from flask import Flask, request, jsonify
import os
import redis

app = Flask(__name__)

REDIS_URL = os.getenv("REDIS_URL", "redis://localhost:6379/0")
ADMIN_API_KEY = os.getenv("ADMIN_API_KEY", "")

r = redis.Redis.from_url(REDIS_URL, decode_responses=True)

SAFE_COMMANDS = {
    "DEL", "EXISTS", "EXPIRE", "EXPIREAT", "TTL", "PTTL", "PERSIST",
    "GET", "MGET", "SET", "MSET", "SETEX", "INCR", "DECR", "INCRBY", "DECRBY",
    "HGET", "HSET", "HDEL", "HGETALL", "HMGET", "HMSET",
    "SADD", "SREM", "SMEMBERS", "SCARD",
    "ZADD", "ZREM", "ZRANGE", "ZREVRANGE", "ZSCORE", "ZCARD",
    "KEYS", "SCAN", "DBSIZE",
    "FLUSHDB", "FLUSHALL",
    "PING", "INFO", "CLIENT", "CONFIG",
}

DENY_PREFIXES = {"SCRIPT", "EVAL", "EVALSHA", "MODULE", "MIGRATE", "REPLICAOF", "SLAVEOF", "ACL", "SHUTDOWN", "DEBUG"}

def _require_auth():
    if not ADMIN_API_KEY:
        return True
    key = request.headers.get("X-API-Key") or request.args.get("api_key") or ""
    return key == ADMIN_API_KEY

def _parse_command(raw: str):
    if raw is None:
        raise ValueError("Missing 'command' parameter")
    raw = raw.strip()
    if not raw:
        raise ValueError("Empty command")
    parts = raw.split()
    return parts

def _is_allowed(cmd_parts):
    cmd = cmd_parts[0].upper()
    if cmd in DENY_PREFIXES:
        return False
    if cmd not in SAFE_COMMANDS:
        return False
    return True

@app.route("/admin/redis/exec", methods=["POST", "GET"])
def redis_exec():
    if not _require_auth():
        return jsonify({"ok": False, "error": "Unauthorized"}), 401

    raw = request.args.get("command", "")
    try:
        cmd_parts = _parse_command(raw)
    except ValueError as e:
        return jsonify({"ok": False, "error": str(e)}), 400

    if not _is_allowed(cmd_parts):
        return jsonify({"ok": False, "error": "Command not allowed"}), 403

    try:
        result = r.execute_command(*cmd_parts)
        return jsonify({"ok": True, "command": cmd_parts, "result": result})
    except redis.RedisError as e:
        return jsonify({"ok": False, "command": cmd_parts, "error": str(e)}), 400
    except Exception as e:
        return jsonify({"ok": False, "command": cmd_parts, "error": "Internal error"}), 500

@app.route("/healthz", methods=["GET"])
def healthz():
    try:
        pong = r.ping()
        return jsonify({"ok": True, "redis": bool(pong)})
    except Exception:
        return jsonify({"ok": False, "redis": False}), 503

